import{_ as e,c as t,o as a,a5 as o}from"./chunks/framework.BTLartk_.js";const f=JSON.parse('{"title":"Frequently Asked Questions","description":"","frontmatter":{},"headers":[],"relativePath":"en/start/questions.md","filePath":"en/start/questions.md","lastUpdated":1734881071000}'),r={name:"en/start/questions.md"},i=o('<h1 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently Asked Questions&quot;">​</a></h1><h2 id="what-is-an-api-key" tabindex="-1">What is an API Key? <a class="header-anchor" href="#what-is-an-api-key" aria-label="Permalink to &quot;What is an API Key?&quot;">​</a></h2><p>After completing the initialization, you can modify/create an API key in the settings interface. The API key is used for authentication in Webhooks. If left blank, the system will randomly generate an API key.</p><h2 id="why-isn-t-my-newly-created-article-displayed-how-does-qexo-ensure-files-are-up-to-date" tabindex="-1">Why isn’t my newly created article displayed? | How does Qexo ensure files are up-to-date? <a class="header-anchor" href="#why-isn-t-my-newly-created-article-displayed-how-does-qexo-ensure-files-are-up-to-date" aria-label="Permalink to &quot;Why isn’t my newly created article displayed? | How does Qexo ensure files are up-to-date?&quot;">​</a></h2><p>Qexo has introduced a caching mechanism to speed up access. You can clear the cache in the settings or set up a Webhook to automatically clear the cache.</p><h2 id="what-is-a-webhook" tabindex="-1">What is a Webhook? <a class="header-anchor" href="#what-is-a-webhook" aria-label="Permalink to &quot;What is a Webhook?&quot;">​</a></h2><p>In Qexo, a Webhook refers to <code>/api/webhook</code> and is used for automated operations, currently available for automatically clearing the cache.</p><h2 id="installation-results-in-a-504-timeout" tabindex="-1">Installation results in a 504 Timeout <a class="header-anchor" href="#installation-results-in-a-504-timeout" aria-label="Permalink to &quot;Installation results in a 504 Timeout&quot;">​</a></h2><ol><li>Your database is either not configured correctly or has not allowed access from all IP addresses in the whitelist. You can modify this in the MongoDB console. <strong>Be sure to redeploy after making changes.</strong></li><li>Delete and recreate the database, ensuring the region is <strong>AWS / N. Virginia (us-east-1)</strong>.</li></ol><h2 id="encountering-a-5xx-error-after-installation-update" tabindex="-1">Encountering a 5xx Error after Installation/Update <a class="header-anchor" href="#encountering-a-5xx-error-after-installation-update" aria-label="Permalink to &quot;Encountering a 5xx Error after Installation/Update&quot;">​</a></h2><p>Each Qexo release undergoes testing in the Dev branch, so major issues are generally rare. If you encounter a 500 or similar error, try the following steps:</p><ol><li>Check database configuration.</li><li>Clear browser cache / program cache.</li><li>On the <code>/settings.html</code> page, check the blog service provider configuration and click save.</li><li>On the <code>/advanced.html</code> page, click the &quot;Repair&quot; button.</li><li>If unable to log in, use the API: <code>/pub/fix?token=(Your API Key)</code>.</li><li>Retain the environment variables for database configuration and redeploy.</li><li>Redeploy the entire program.</li><li>Try the Dev branch.</li></ol><h2 id="assertionerror-xxx-object-its-id-attribute-is-set-to-none" tabindex="-1">AssertionError(&quot;xxx object ... its id attribute is set to None.&quot;) <a class="header-anchor" href="#assertionerror-xxx-object-its-id-attribute-is-set-to-none" aria-label="Permalink to &quot;AssertionError(&quot;xxx object ... its id attribute is set to None.&quot;)&quot;">​</a></h2><p>Check if you&#39;ve ever used version 0.01 or 0.1. These versions have serious issues. Please recreate the database and redeploy.</p><h2 id="how-to-create-an-article-in-a-subdirectory" tabindex="-1">How to create an article in a subdirectory <a class="header-anchor" href="#how-to-create-an-article-in-a-subdirectory" aria-label="Permalink to &quot;How to create an article in a subdirectory&quot;">​</a></h2><p>In the article name field, fill in <code>dir/filename</code>. For example, if you want to create <code>source/_posts/about/me.md</code>, you need to enter <code>about/me</code>.</p><h2 id="keyerror-xxx" tabindex="-1">KeyError: &#39;XXX&#39; <a class="header-anchor" href="#keyerror-xxx" aria-label="Permalink to &quot;KeyError: &#39;XXX&#39;&quot;">​</a></h2><p>This indicates that the &quot;XXX&quot; environment variable was not obtained. Please add it according to the table below and then Redeploy.</p><table tabindex="0"><thead><tr><th>Name</th><th>Meaning</th><th>Example</th></tr></thead><tbody><tr><td>DOMAINS</td><td>The allowed secure domain names for communication. Note the double quotes and English half-width characters.</td><td>[&quot;.vercel.app&quot;, &quot;127.0.0.1&quot;, &quot;.yoursite.com&quot;]</td></tr><tr><td>MONGODB_HOST</td><td>MongoDB database connection address</td><td>mongodb+srv://cluster0.xxxx.mongodb.net</td></tr><tr><td>MONGODB_PORT</td><td>MongoDB database communication port, default is 27017</td><td>27017</td></tr><tr><td>MONGODB_USER</td><td>MongoDB database username</td><td>abudu</td></tr><tr><td>MONGODB_DB</td><td>MongoDB database name</td><td>Cluster0</td></tr><tr><td>MONGODB_PASS</td><td>MongoDB database password</td><td>JWo0xxxxxxxx</td></tr></tbody></table><h2 id="github-configuration-validation-errors" tabindex="-1">GitHub configuration validation errors <a class="header-anchor" href="#github-configuration-validation-errors" aria-label="Permalink to &quot;GitHub configuration validation errors&quot;">​</a></h2><p>If you encounter problems in the configuration, you can visit the <a href="https://hexoplusplus.cronfly.workers.dev/?step=start" target="_blank" rel="noreferrer">HPP Validation Helper</a> to self-check the configuration. If confirmed correct, check if there are already published articles in the repository.</p><p>Note: The GitHub repository must be the one used for <strong>automated deployment</strong> of your blog source code.</p><h2 id="vercel-usage-issues" tabindex="-1">Vercel usage issues <a class="header-anchor" href="#vercel-usage-issues" aria-label="Permalink to &quot;Vercel usage issues&quot;">​</a></h2><p>Vercel&#39;s serverless function usage is sufficient for Qexo, but it can&#39;t stop malicious attacks. Therefore, it&#39;s important to protect your backend address. Fortunately, Vercel won&#39;t charge you without permission, so after resources are depleted, no fees will be incurred. If you&#39;re still concerned, you can consider deploying on your own server <a href="https://github.com/am-abudu/Qexo/wiki/%E6%9C%8D%E5%8A%A1%E5%99%A8%E9%83%A8%E7%BD%B2" target="_blank" rel="noreferrer">#Server Deployment#</a>.</p><h2 id="online-update-failed" tabindex="-1">Online update failed <a class="header-anchor" href="#online-update-failed" aria-label="Permalink to &quot;Online update failed&quot;">​</a></h2><p>Check whether the VERCEL_TOKEN and PROJECT_ID in advanced settings are correctly set for the Qexo deployment project.</p><h2 id="other-issues" tabindex="-1">Other Issues <a class="header-anchor" href="#other-issues" aria-label="Permalink to &quot;Other Issues&quot;">​</a></h2><p>If you have more questions, you can submit an <a href="https://github.com/am-abudu/Qexo/issues" target="_blank" rel="noreferrer">issue</a> or join the <a href="https://jq.qq.com/?_wv=1027&amp;k=rAcnhzqK" target="_blank" rel="noreferrer">HexoPlusPlus community group</a> to ask.</p>',28),n=[i];function s(l,d,c,u,h,p){return a(),t("div",null,n)}const m=e(r,[["render",s]]);export{f as __pageData,m as default};
